/* ════ ui/form/combobox.js ════ */
// EF.ui.combobox — text input + filtered dropdown.
//
// opts: { value: signal<string>, options: string[] | [{value,label}], placeholder? }
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  function norm(items) {
    return (items || []).map(function (it) {
      if (typeof it === 'string') return { value: it, label: it }
      return it
    })
  }

  ui.combobox = function (opts) {
    const o = opts || {}
    const sig = ui.asSig(o.value != null ? o.value : '')
    const items = norm(o.options)
    const wrap = ui.h('div', 'ef-ui-field ef-ui-combobox')
    const inp = ui.h('input', 'ef-ui-input', { type: 'text', placeholder: o.placeholder || '' })
    const arrow = ui.h('span', 'ef-ui-field-suffix', { text: '▾' })
    wrap.appendChild(inp); wrap.appendChild(arrow)
    ui.bind(wrap, sig, function (v) { if (document.activeElement !== inp) inp.value = v == null ? '' : String(v) })

    let pop = null
    function open() {
      if (pop) return
      const list = ui.h('div', 'ef-ui-menu')
      const term = inp.value.toLowerCase()
      const filtered = items.filter(function (it) { return !term || String(it.label).toLowerCase().indexOf(term) >= 0 })
      if (!filtered.length) {
        const empty = ui.h('div', 'ef-ui-menu-empty', { text: 'No matches' })
        list.appendChild(empty)
      }
      for (let i = 0; i < filtered.length; i++) {
        const it = filtered[i]
        const row = ui.h('button', 'ef-ui-menu-item', { type: 'button', text: it.label })
        row.addEventListener('mousedown', function (e) { e.preventDefault(); sig.set(it.value); inp.value = it.value; close() })
        list.appendChild(row)
      }
      list.style.minWidth = wrap.getBoundingClientRect().width + 'px'
      list.style.maxHeight = '240px'; list.style.overflow = 'auto'
      pop = ui.popover({ anchor: wrap, content: list, side: 'bottom', align: 'start', onDismiss: function () { pop = null } })
    }
    function close() { if (pop) { pop.close(); pop = null } }
    function reopen() { close(); open() }

    inp.addEventListener('focus', open)
    inp.addEventListener('input', function () { sig.set(inp.value); reopen() })
    arrow.addEventListener('mousedown', function (e) { e.preventDefault(); inp.focus(); pop ? close() : open() })
    ui.collect(wrap, close)

    return wrap
  }
})(window.EF = window.EF || {})

/* ════ ui/form/colorInput.js ════ */
// EF.ui.colorInput — color swatch + popover with HSV picker + hex input.
//
// opts: { value: signal<string>, format?: 'hex' | 'rgba' }   (default 'hex')
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  ui.colorInput = function (opts) {
    const o = opts || {}
    const sig = ui.asSig(o.value != null ? o.value : '#7b6ef6')

    const el = ui.h('div', 'ef-ui-color')
    const swatch = ui.h('div', 'ef-ui-color-swatch')
    const text = ui.h('input', 'ef-ui-color-text', { type: 'text' })
    el.appendChild(swatch); el.appendChild(text)

    ui.bind(el, sig, function (v) {
      swatch.style.background = v
      if (document.activeElement !== text) text.value = v
    })
    text.addEventListener('input', function () {
      const v = text.value.trim()
      if (/^#[0-9a-f]{6}$/i.test(v) || /^#[0-9a-f]{3}$/i.test(v)) sig.set(v)
    })

    let pop = null
    swatch.addEventListener('click', function () {
      if (pop) { pop.close(); pop = null; return }
      pop = openPicker(el, sig, function () { pop = null })
    })
    // If the widget is disposed while the picker is open, tear it down.
    ui.collect(el, function () { if (pop) { pop.close(); pop = null } })
    return el
  }

  // ── HSV picker popover ─────────────────────────────────────────
  function openPicker(anchor, sig, onClose) {
    const wrap = ui.h('div', 'ef-ui-color-picker')

    const hsv = hexToHsv(sig.peek()) || { h: 0, s: 1, v: 1 }
    const sigH = EF.signal(hsv.h)
    const sigS = EF.signal(hsv.s)
    const sigV = EF.signal(hsv.v)

    // SV square
    const sv = ui.h('div', 'ef-ui-color-sv')
    const svDot = ui.h('div', 'ef-ui-color-sv-dot')
    sv.appendChild(svDot)
    // Hue strip
    const hue = ui.h('div', 'ef-ui-color-hue')
    const hueDot = ui.h('div', 'ef-ui-color-hue-dot')
    hue.appendChild(hueDot)
    // Hex input
    const hex = ui.h('input', 'ef-ui-color-hex', { type: 'text' })

    wrap.appendChild(sv); wrap.appendChild(hue); wrap.appendChild(hex)

    function update() {
      sv.style.background = 'linear-gradient(to top, #000, transparent), linear-gradient(to right, #fff, hsl(' +
                            (sigH.peek() * 360) + ',100%,50%))'
      svDot.style.left = (sigS.peek() * 100) + '%'
      svDot.style.top  = ((1 - sigV.peek()) * 100) + '%'
      hueDot.style.left = (sigH.peek() * 100) + '%'
      const out = hsvToHex(sigH.peek(), sigS.peek(), sigV.peek())
      sig.set(out)
      if (document.activeElement !== hex) hex.value = out
    }
    const stopEffect = EF.effect(function () { sigH(); sigS(); sigV(); update() })

    ui.attachDrag(sv, {
      onStart: scrubSv, onMove: scrubSv,
    })
    function scrubSv(e) {
      const r = sv.getBoundingClientRect()
      sigS.set(Math.max(0, Math.min(1, (e.clientX - r.left) / r.width)))
      sigV.set(Math.max(0, Math.min(1, 1 - (e.clientY - r.top) / r.height)))
    }
    ui.attachDrag(hue, {
      onStart: scrubHue, onMove: scrubHue,
    })
    function scrubHue(e) {
      const r = hue.getBoundingClientRect()
      sigH.set(Math.max(0, Math.min(1, (e.clientX - r.left) / r.width)))
    }
    hex.addEventListener('input', function () {
      const h = hexToHsv(hex.value.trim())
      if (h) { sigH.set(h.h); sigS.set(h.s); sigV.set(h.v) }
    })

    return ui.popover({
      anchor: anchor, content: wrap, side: 'bottom', align: 'start',
      onDismiss: function () { stopEffect(); onClose && onClose() },
    })
  }

  // ── color math ─────────────────────────────────────────────────
  function hexToHsv(hex) {
    if (!hex) return null
    let m = /^#?([0-9a-f]{3}|[0-9a-f]{6})$/i.exec(hex)
    if (!m) return null
    let h = m[1]
    if (h.length === 3) h = h[0]+h[0]+h[1]+h[1]+h[2]+h[2]
    const r = parseInt(h.slice(0,2), 16) / 255
    const g = parseInt(h.slice(2,4), 16) / 255
    const b = parseInt(h.slice(4,6), 16) / 255
    const mx = Math.max(r,g,b), mn = Math.min(r,g,b), d = mx - mn
    let H = 0
    if (d > 0) {
      if (mx === r) H = ((g - b) / d) % 6
      else if (mx === g) H = (b - r) / d + 2
      else H = (r - g) / d + 4
      H = (H * 60 + 360) % 360 / 360
    }
    const S = mx === 0 ? 0 : d / mx
    const V = mx
    return { h: H, s: S, v: V }
  }
  function hsvToHex(h, s, v) {
    const i = Math.floor(h * 6)
    const f = h * 6 - i
    const p = v * (1 - s)
    const q = v * (1 - f * s)
    const t = v * (1 - (1 - f) * s)
    let r, g, b
    switch (i % 6) {
      case 0: r = v; g = t; b = p; break
      case 1: r = q; g = v; b = p; break
      case 2: r = p; g = v; b = t; break
      case 3: r = p; g = q; b = v; break
      case 4: r = t; g = p; b = v; break
      case 5: r = v; g = p; b = q; break
    }
    function h2(x) { return ('0' + Math.round(x * 255).toString(16)).slice(-2) }
    return '#' + h2(r) + h2(g) + h2(b)
  }
})(window.EF = window.EF || {})

