      const PAD = 12
      const innerW = W - PAD * 2, innerH = H - PAD * 2
      const x = Math.max(0, Math.min(1, (e.clientX - r.left - PAD) / innerW))
      const y = Math.max(-.5, Math.min(1.5, 1 - (e.clientY - r.top - PAD) / innerH))
      const v = sig.peek().slice()
      v[dragIdx * 2]     = x
