/* ════ ui/data/breadcrumbs.js ════ */
// EF.ui.breadcrumbs — path crumbs with click handlers.
//
// opts: { items: [{ label, onClick? }] | signal<...> , separator? }
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  ui.breadcrumbs = function (opts) {
    const o = opts || {}
    const items = ui.asSig(o.items != null ? o.items : [])
    const sep = o.separator || '›'
    const el = ui.h('nav', 'ef-ui-crumbs')
    function rebuild(arr) {
      el.replaceChildren()
      for (let i = 0; i < arr.length; i++) {
        const it = arr[i]
        const isLast = i === arr.length - 1
        const node = it.onClick ? ui.h('button', 'ef-ui-crumbs-link', { type: 'button', text: it.label }) : ui.h('span', 'ef-ui-crumbs-static', { text: it.label })
        if (it.onClick) node.addEventListener('click', it.onClick)
        if (isLast) node.classList.add('ef-ui-crumbs-last')
        el.appendChild(node)
        if (!isLast) el.appendChild(ui.h('span', 'ef-ui-crumbs-sep', { text: sep }))
      }
    }
    ui.bind(el, items, rebuild)
    return el
  }
})(window.EF = window.EF || {})

/* ════ ui/data/progressBar.js ════ */
// EF.ui.progressBar — determinate progress bar (0..1) or indeterminate.
//
// opts: { value: signal<number> | number, indeterminate?, label? }
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  ui.progressBar = function (opts) {
    const o = opts || {}
    const el = ui.h('div', 'ef-ui-progress' + (o.indeterminate ? ' ef-ui-progress-ind' : ''))
    const fill = ui.h('div', 'ef-ui-progress-fill')
    el.appendChild(fill)
    if (o.label != null) {
      const lab = ui.h('span', 'ef-ui-progress-label', { text: String(o.label) })
      el.appendChild(lab)
    }
    if (o.value != null) {
      const sig = ui.asSig(o.value)
      ui.bind(el, sig, function (v) {
        const p = Math.max(0, Math.min(1, Number(v) || 0))
        fill.style.width = (p * 100) + '%'
      })
    }
    return el
  }
})(window.EF = window.EF || {})

/* ════ ui/overlay/menu.js ════ */
// EF.ui.menu — context / dropdown menu.
//
// This is just a normal UI widget; the framework does NOT bind global menu
// hotkeys or right-click handlers. Callers wire it up: pointerdown / Ctrl+K /
// button click → call EF.ui.menu({ ... }) to open it.
//
// opts:
//   anchor   : HTMLElement                    required (popover anchor)
//   items    : MenuItem[]
//                MenuItem = { label, icon?, kbd?, onSelect?, disabled?, danger? }
//                         | { type: 'divider' }
//                         | { type: 'header', label }
//                         | { label, items: MenuItem[] }    nested submenu
//   side?, align?
//
// Returns a popover handle.
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  function buildMenu(items, onClose) {
    const list = ui.h('div', 'ef-ui-menu')
    for (let i = 0; i < items.length; i++) {
      const it = items[i]
      if (it.type === 'divider') {
        list.appendChild(ui.h('div', 'ef-ui-menu-divider'))
        continue
      }
      if (it.type === 'header') {
        list.appendChild(ui.h('div', 'ef-ui-menu-header', { text: it.label }))
        continue
      }
      const row = ui.h('button', 'ef-ui-menu-item' +
        (it.disabled ? ' ef-ui-menu-item-disabled' : '') +
        (it.danger ? ' ef-ui-menu-item-danger' : ''),
        { type: 'button' })
      if (it.icon) row.appendChild(ui.icon({ glyph: it.icon, size: 'sm' }))
      const labelEl = ui.h('span', 'ef-ui-menu-item-label', { text: it.label || '' })
      row.appendChild(labelEl)
      if (it.kbd) {
        const k = ui.kbd(it.kbd)
        k.classList.add('ef-ui-menu-item-kbd')
        row.appendChild(k)
      }
      if (it.items && it.items.length) {
        const arrow = ui.h('span', 'ef-ui-menu-item-sub', { text: '▸' })
        row.appendChild(arrow)
        let subPop = null
        row.addEventListener('mouseenter', function () {
          if (subPop) return
          const sub = buildMenu(it.items, onClose)
          subPop = ui.popover({ anchor: row, content: sub, side: 'right', align: 'start' })
        })
        row.addEventListener('mouseleave', function () {
          // submenu has its own dismiss-on-outside; let it manage itself
        })
      } else {
        row.addEventListener('click', function () {
          if (it.disabled) return
          if (it.onSelect) it.onSelect()
          onClose && onClose()
        })
      }
      list.appendChild(row)
    }
    return list
  }

  ui.menu = function (opts) {
    const o = opts || {}
    let pop = null
    function close() { if (pop) { pop.close(); pop = null } }
    const list = buildMenu(o.items || [], close)
    pop = ui.popover({ anchor: o.anchor, content: list, side: o.side || 'bottom', align: o.align || 'start' })
    return pop
  }
})(window.EF = window.EF || {})

/* ════ ui/overlay/modal.js ════ */
// EF.ui.modal — centered modal dialog with backdrop.
//
// EF.ui.modal({ title, content: HTMLElement, footer?: HTMLElement, onClose? })
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  ui.modal = function (opts) {
    const o = opts || {}
    const back = ui.h('div', 'ef-ui-modal-backdrop')
    const box  = ui.h('div', 'ef-ui-modal')
    if (o.title) {
      const head = ui.h('div', 'ef-ui-modal-head')
      head.appendChild(ui.h('span', 'ef-ui-modal-title', { text: o.title }))
      const x = ui.h('button', 'ef-ui-modal-close', { type: 'button', text: '×' })
      x.addEventListener('click', function () { close() })
      head.appendChild(x)
      box.appendChild(head)
    }
    const body = ui.h('div', 'ef-ui-modal-body')
    if (o.content) body.appendChild(o.content)
    box.appendChild(body)
    if (o.footer) {
      const foot = ui.h('div', 'ef-ui-modal-foot')
      foot.appendChild(o.footer)
      box.appendChild(foot)
    }
    back.appendChild(box)
    const unmount = ui.portal(back)
    function onKey(e) { if (e.key === 'Escape') close() }
    document.addEventListener('keydown', onKey)
    back.addEventListener('mousedown', function (e) { if (e.target === back) close() })

    let closed = false
    function close() {
      if (closed) return
      closed = true
      document.removeEventListener('keydown', onKey)
      unmount()
      o.onClose && o.onClose()
    }
    return { el: box, close: close }
  }
})(window.EF = window.EF || {})

/* ════ ui/overlay/drawer.js ════ */
// EF.ui.drawer — slide-in side panel.
//
// EF.ui.drawer({ side?: 'right'|'left'|'top'|'bottom', title?, content, onClose? })
;(function (EF) {
  'use strict'
  const ui = EF.ui = EF.ui || {}

  ui.drawer = function (opts) {
    const o = opts || {}
    const side = o.side || 'right'
    const back = ui.h('div', 'ef-ui-drawer-backdrop')
    const panel = ui.h('div', 'ef-ui-drawer ef-ui-drawer-' + side)
    if (o.title) {
      const head = ui.h('div', 'ef-ui-drawer-head')
      head.appendChild(ui.h('span', 'ef-ui-drawer-title', { text: o.title }))
      const x = ui.h('button', 'ef-ui-modal-close', { type: 'button', text: '×' })
      x.addEventListener('click', function () { close() })
      head.appendChild(x)
      panel.appendChild(head)
    }
    const body = ui.h('div', 'ef-ui-drawer-body')
    if (o.content) body.appendChild(o.content)
    panel.appendChild(body)
    back.appendChild(panel)
    const unmount = ui.portal(back)
    requestAnimationFrame(function () { panel.classList.add('ef-ui-drawer-open') })
    function onKey(e) { if (e.key === 'Escape') close() }
    document.addEventListener('keydown', onKey)
    back.addEventListener('mousedown', function (e) { if (e.target === back) close() })

    let closed = false
    function close() {
      if (closed) return
      closed = true
      document.removeEventListener('keydown', onKey)
      panel.classList.remove('ef-ui-drawer-open')
      setTimeout(function () { unmount(); o.onClose && o.onClose() }, 220)
    }
    return { el: panel, close: close }
  }
})(window.EF = window.EF || {})

/* ════ ui/overlay/alert.js ════ */
// EF.ui.alert — inline alert/banner (not a modal).
//
